ON CONFLICT (slug) DO NOTHING;


-- ============================================================================
-- §LEGACY-MIGRATION  (only AFTER §3c creates target tags)
-- ============================================================================
-- Migrates 4 wlad + 1 pra associations to the newly-created legal-framework
-- counterparts, then drops the legacy NULL-category tag rows. The other 5
-- NULL-category legacy tags (galvin, galvin-dual-role, snohomish-county-
-- legal-services, legal-automation, athena-paralegal) are untouched per
-- operator decision (deferred to a separate tag-hygiene task).

-- Migrate legacy wlad (id=242) → new legal-framework:wlad
INSERT INTO core.document_tags (document_id, tag_id)
SELECT dt.document_id,
       (SELECT id FROM core.tags WHERE category='legal-framework' AND slug='wlad')
FROM core.document_tags dt
WHERE dt.tag_id = 242
ON CONFLICT (document_id, tag_id) DO NOTHING;

-- Migrate legacy pra (id=606) → new legal-framework:pra
INSERT INTO core.document_tags (document_id, tag_id)
SELECT dt.document_id,
       (SELECT id FROM core.tags WHERE category='legal-framework' AND slug='pra')
FROM core.document_tags dt
WHERE dt.tag_id = 606
ON CONFLICT (document_id, tag_id) DO NOTHING;

-- Drop legacy associations (5 join rows: 4 wlad + 1 pra)
DELETE FROM core.document_tags WHERE tag_id IN (242, 606);

-- Drop now-orphaned legacy tag rows
DELETE FROM core.tags WHERE id IN (242, 606);


-- ============================================================================
-- §4  USC RETROACTIVE TAGGING — apply `code-jurisdiction:federal-usc` to all
--                                11,678 existing USC documents
-- ============================================================================
-- Anchor: every USC doc carries the existing `usc-meta:usc` tag. Use it as
-- the predicate selector. ON CONFLICT against the (document_id, tag_id) PK
-- makes this idempotent.

INSERT INTO core.document_tags (document_id, tag_id)
SELECT
  dt.document_id,
  (SELECT id FROM core.tags
    WHERE category='code-jurisdiction' AND slug='federal-usc') AS tag_id
FROM core.document_tags dt
JOIN core.tags t ON t.id = dt.tag_id
WHERE t.category='usc-meta' AND t.slug='usc'
ON CONFLICT (document_id, tag_id) DO NOTHING;


-- ============================================================================
-- §POST-APPLY GUARDS (raise EXCEPTION on mismatch — triggers rollback)
-- ============================================================================
-- Final sanity checks INSIDE the transaction. If any check fails, the entire
-- transaction rolls back and the database is unchanged.
--
-- Note: the slug check below uses the bare slug 'federal-usc' (NOT the
-- category-prefixed form) because that's how §3a inserts it. Slug is unique
-- globally; category is a separate column. Pairing both in the WHERE is the
-- canonical lookup pattern.

DO $$
DECLARE
  wlad_migrated         INTEGER;
  pra_migrated          INTEGER;
  legacy_tag_rows_left  INTEGER;
  legacy_join_rows_left INTEGER;
  usc_tagged            INTEGER;
  rcw_tables_present    INTEGER;
  new_tag_count         INTEGER;
BEGIN
  -- Post.1 All 4 originally-wlad-tagged docs now carry legal-framework:wlad
  SELECT COUNT(*) INTO wlad_migrated FROM core.document_tags dt
  JOIN core.tags t ON t.id = dt.tag_id
  WHERE t.category='legal-framework' AND t.slug='wlad'
  AND dt.document_id IN (
    '228abe05-8607-4ed0-a432-c4f1e4ab3902',
    '319c0009-efa4-4dd1-90c6-5b8a28d506d3',
    '7c695a5f-b7db-490d-879a-a6fa47b0770b',
    '84cbd52d-95bd-4e6a-af6d-c21508936434'
  );
  IF wlad_migrated <> 4 THEN
    RAISE EXCEPTION 'Post-apply FAIL [Post.1]: WLAD migration count = %, expected 4. Rolling back.', wlad_migrated;
  END IF;

  -- Post.2 The single pra doc carries legal-framework:pra
  SELECT COUNT(*) INTO pra_migrated FROM core.document_tags dt
  JOIN core.tags t ON t.id = dt.tag_id
  WHERE t.category='legal-framework' AND t.slug='pra'
  AND dt.document_id = '228abe05-8607-4ed0-a432-c4f1e4ab3902';
  IF pra_migrated <> 1 THEN
    RAISE EXCEPTION 'Post-apply FAIL [Post.2]: PRA migration count = %, expected 1. Rolling back.', pra_migrated;
  END IF;

  -- Post.3 Legacy tag rows (id=242, id=606) are gone from core.tags
  SELECT COUNT(*) INTO legacy_tag_rows_left FROM core.tags WHERE id IN (242, 606);
  IF legacy_tag_rows_left <> 0 THEN
    RAISE EXCEPTION 'Post-apply FAIL [Post.3]: legacy tag rows still present in core.tags (count=%). Rolling back.', legacy_tag_rows_left;
  END IF;

  -- Post.4 Legacy join rows (tag_id=242, tag_id=606) are gone from core.document_tags
  SELECT COUNT(*) INTO legacy_join_rows_left FROM core.document_tags WHERE tag_id IN (242, 606);
  IF legacy_join_rows_left <> 0 THEN
    RAISE EXCEPTION 'Post-apply FAIL [Post.4]: legacy join rows still present in core.document_tags (count=%). Rolling back.', legacy_join_rows_left;
  END IF;

  -- Post.5 All 11,678 USC docs carry code-jurisdiction:federal-usc
  -- (note: WHERE pairs both category and slug — slug alone is globally unique
  -- but the pair is the canonical lookup form; same-row lookup either way)
  SELECT COUNT(*) INTO usc_tagged FROM core.document_tags dt
  JOIN core.tags t ON t.id = dt.tag_id
  WHERE t.category='code-jurisdiction' AND t.slug='federal-usc';
  IF usc_tagged <> 11678 THEN
    RAISE EXCEPTION 'Post-apply FAIL [Post.5]: USC retro-tag count = %, expected 11678. Rolling back.', usc_tagged;
  END IF;

  -- Post.6 All 7 rcw.* tables exist
  SELECT COUNT(*) INTO rcw_tables_present FROM information_schema.tables
    WHERE table_schema='rcw'
      AND table_name IN ('titles','chapters','sections','cross_references',
                          'section_history','section_notes','ingestion_runs');
  IF rcw_tables_present <> 7 THEN
    RAISE EXCEPTION 'Post-apply FAIL [Post.6]: rcw.* table count = %, expected 7. Rolling back.', rcw_tables_present;
  END IF;

  -- Post.7 New tag rows: 2 code-jurisdiction + 8 rcw-meta + 17 legal-framework
  --        (RCW additions, net of existing 28) + 100 rcw-title = 127 new rows
  --        in those four categories, minus the 2 legacy rows we removed = net
  --        addition of 125. We measure new total: existing 28 legal-framework
  --        - 0 (we didn't remove any in that category — wlad/pra were NULL-
  --        category) + 17 = 45 in legal-framework. Plus the 4 new categories
  --        with 2+8+100 = 110. Easier to count as a positive existence check:
  SELECT
    (SELECT COUNT(*) FROM core.tags WHERE category='code-jurisdiction')
    + (SELECT COUNT(*) FROM core.tags WHERE category='rcw-meta')
    + (SELECT COUNT(*) FROM core.tags WHERE category='rcw-title')
    INTO new_tag_count;
  IF new_tag_count <> 110 THEN
    RAISE EXCEPTION 'Post-apply FAIL [Post.7]: new tag categories total = %, expected 110 (2 code-jurisdiction + 8 rcw-meta + 100 rcw-title). Rolling back.', new_tag_count;
  END IF;

  RAISE NOTICE 'Post-apply guards: PASS (wlad migrated=4, pra migrated=1, legacy gone, USC tagged=11678, 7 rcw.* tables, 110 tag rows in new categories)';
END $$;


-- ============================================================================
-- COMMIT
-- ============================================================================
-- If we got here, all guards passed. COMMIT makes the changes durable.
-- If any guard above raised EXCEPTION, the transaction was already rolled back
-- by ON_ERROR_STOP and this COMMIT is skipped.

COMMIT;


-- ============================================================================
-- §5  POST-COMMIT VERIFICATION SELECTS
-- ============================================================================
-- These run AFTER the transaction commits, in autocommit mode. Their results
-- print to stdout for the operator to inspect. They are read-only and any
-- failure here does NOT roll back the apply (already committed).
--
-- Operator: paste the entire psql output (including these results) back to
-- the agent for parsing and Phase 2 authorization decision.

\echo '--- §5.1 rcw schema and 7 tables exist ---'
SELECT
  EXISTS (SELECT 1 FROM information_schema.schemata WHERE schema_name='rcw')                                 AS rcw_schema,
  EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='rcw' AND table_name='titles')          AS titles_tbl,
  EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='rcw' AND table_name='chapters')        AS chapters_tbl,
  EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='rcw' AND table_name='sections')        AS sections_tbl,
  EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='rcw' AND table_name='cross_references') AS xref_tbl,
  EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='rcw' AND table_name='section_history') AS history_tbl,
  EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='rcw' AND table_name='section_notes')   AS notes_tbl,
  EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='rcw' AND table_name='ingestion_runs')  AS runs_tbl;

\echo ''
\echo '--- §5.2 Tag pre-seeds inserted ---'
SELECT
  (SELECT COUNT(*) FROM core.tags WHERE category='code-jurisdiction')   AS code_jurisdiction_n,    -- expect 2
  (SELECT COUNT(*) FROM core.tags WHERE category='rcw-meta')            AS rcw_meta_n,             -- expect 8
  (SELECT COUNT(*) FROM core.tags WHERE category='rcw-title')           AS rcw_title_n,            -- expect 100
  (SELECT COUNT(*) FROM core.tags WHERE category='legal-framework')     AS legal_framework_total;  -- expect 28 + 17 = 45

\echo ''
\echo '--- §5.3 USC retroactive tagging count ---'
SELECT COUNT(*) AS usc_docs_with_code_jurisdiction
FROM core.document_tags dt
JOIN core.tags t ON t.id = dt.tag_id
WHERE t.category='code-jurisdiction' AND t.slug='federal-usc';
-- expect: 11678

\echo ''
\echo '--- §5.4 [Additional] Legacy tag rows are gone ---'
SELECT COUNT(*) AS should_be_zero FROM core.tags WHERE id IN (242, 606);
-- expect: 0

\echo ''
\echo '--- §5.5 [Additional] All 4 wlad-tagged docs have new legal-framework:wlad ---'
SELECT COUNT(*) AS should_be_4 FROM core.document_tags dt
JOIN core.tags t ON t.id = dt.tag_id
WHERE t.category='legal-framework' AND t.slug='wlad'
AND dt.document_id IN (
  '228abe05-8607-4ed0-a432-c4f1e4ab3902',
  '319c0009-efa4-4dd1-90c6-5b8a28d506d3',
  '7c695a5f-b7db-490d-879a-a6fa47b0770b',
  '84cbd52d-95bd-4e6a-af6d-c21508936434'
);
-- expect: 4

\echo ''
\echo '--- §5.6 [Additional] 228abe05 retains pra under new categorized tag ---'
SELECT COUNT(*) AS should_be_1 FROM core.document_tags dt
JOIN core.tags t ON t.id = dt.tag_id
WHERE t.category='legal-framework' AND t.slug='pra'
AND dt.document_id='228abe05-8607-4ed0-a432-c4f1e4ab3902';
-- expect: 1

\echo ''
\echo '--- §5.7 The non-colliding legacy tags are STILL PRESENT (deferred hygiene) ---'
SELECT t.id, t.name, COUNT(dt.document_id) AS docs_associated
FROM core.tags t
LEFT JOIN core.document_tags dt ON dt.tag_id = t.id
WHERE t.id IN (488, 597, 256, 340, 718)
GROUP BY t.id, t.name
ORDER BY t.id;
-- expect: 5 rows (galvin-dual-role, galvin, legal-automation, athena-paralegal, snohomish-county-legal-services)
-- with their original document association counts (1, 4, 2, 1, 1 respectively).

\echo ''
\echo '--- §5.8 Existing jurisdiction:wa:ada is untouched ---'
SELECT id, slug, name, category FROM core.tags
WHERE category='jurisdiction' AND slug='wa:ada';
-- expect: 1 row, exactly as it was before apply

\echo ''
\echo '=== END schema_apply.sql ==='
\echo 'Capture complete output and paste to agent for Phase 2 authorization.'

-- ============================================================================
-- END OF FILE
-- ============================================================================
